            text: 'El producto se creó correctamente',
            timer: 2000,
            showConfirmButton: false
          });
          this.cargarProductos();
          this.cdr.detectChanges();
          this.cancelar();
        },
        error: error => console.error('Error al crear', error)
      });
    }
